module siso_shift_register (  
    input wire clk,  
    input wire reset,  
    input wire data_in,  
    output reg [4:0] data_out  
);  

    reg [4:0] reverse_reg;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            reverse_reg <= 5'b00000;  
            data_out <= 5'b00000;  
        end else begin  
            reverse_reg <= {reverse_reg[3:0], data_in};  
            data_out <= reverse_reg;  
        end  
    end  
endmodule
